VALUES
  ('bookkeeper-moex-00312', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依遺產及贈與稅法相關規定，下列有關繼承財產為已在證券交易所上市之有價證券（以下簡稱上市股 票）價值估定方式，何者錯誤？', '["繼承開始日該上市股票有買賣價格者，依該日該上市股票之收盤價估定", "繼承開始日該上市股票無買賣價格者，依該日前最後一日該上市股票之收盤價估定", "繼承開始日為該上市股票除權除息日者，依該日後一個月內該上市股票各日收盤價之平均價格估定", "繼承開始日該上市股票價格有劇烈變動者，依繼承開始日前一個月內該上市股票各日收盤價之平均 價格估定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00313', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '關於遺產稅及贈與稅之申報規定，下列敘述何者正確？', '["遺產稅應由納稅義務人於被繼承人死亡之日起6個月內，向死亡地主管稽徵機關申報", "贈與人在一年內贈與他人之財產總值超過贈與稅免稅額時，應於超過免稅額之贈與行為發生後 30 日內，向主管稽徵機關辦理申報", "同一贈與人在同一年內有兩次以上應申報納稅之贈與行為者，應分別申報計徵贈與稅", "稽徵機關於查悉死亡事實後，應於10日內通知依限申報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00314', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '郭君結婚時，其祖父、父親、母親及大哥各自分別贈與現金100萬元。依遺產及贈與稅法第20條規 定，前述贈與得「不計入贈與總額」之金額為多少？', '["100萬元", "200萬元", "244萬元", "400萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00315', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '記帳士受委任後，非有正當事由，不得終止其契約；如須終止契約，記帳士應於幾日前通知委任人？', '["7日", "10日", "15日", "30日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00316', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '不得充任記帳士之情形，下列何者不在範圍之內？', '["曾因業務上有詐欺、背信、侵占、偽造文書等犯罪行為，受有期徒刑一年以上刑之裁判確定", "受破產之宣告尚未復權", "曾服公職", "受監護或輔助宣告尚未撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00317', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '有關記帳士在其他直轄市、縣市執行業務時，下列規定何者正確？', '["免向主管機關登記，免設分事務所", "免向主管機關登記，應設分事務所", "應向主管機關登記，應設分事務所", "應向主管機關登記，免設分事務所"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00318', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '記帳士若違反記帳士暨記帳及報稅代理人防制洗錢與打擊資恐辦法規定，其相關之裁處及調查由下列 何機關辦理？', '["法務部調查局", "財政部委任各地區國稅局", "經濟部商業司", "金融監督管理委員會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00319', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '張無忌於 107 年以前任職財政部中區國稅局彰化分局，109 年調任財政部北區國稅局新竹分局，110 年1月4日轉任桃園市政府地方稅務局，在各稅捐機關任職期間皆擔任稅務職系稅務員，於111年1 月4日轉任財政部臺北國稅局主計室隨後於112年1月1日從臺北國稅局主計室會計股辦理退休離 職，張員於110年考取記帳士並取得記帳士證書並準備於112年2月1日起執業，請問張員於112年 2月當下不得於何縣、市區域內執行記帳士職務？', '["桃園市", "桃園市、臺北市", "新竹市、桃園市、臺北市", "彰化縣、新竹市、桃園市、臺北市"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00320', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '李記帳士係臺北市記帳士公會會員，依據記帳士法之規定，記帳士不得在登錄區域內，執行下列那項 業務？', '["受委任辦理營業、變更、註銷、停業、復業及其他登記事項", "受委任辦理各項稅捐稽徵案件之申報及申請事項", "受委任辦理商業會計事務", "受委任提起訴願、行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00321', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '記帳士某甲，因逃漏稅捐，經稅捐稽徵機關處分有案，記帳士懲戒委員會決議書於112年10月18日 送達，若某甲不服，應於何時前向記帳士懲戒覆審委員會請求覆審？', '["112年11月6日", "112年11月7日", "112年11月16日", "112年11月17日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00322', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '張三111年11月記帳士考試及格，準備在高雄市左營區設立事務所執業，請問與其有關之相關機關，', '["登錄執業機關為財政部高雄國稅局", "記帳士證書由考選部核發", "記帳士主管 機關為高雄市政府", "稅務部分業務事件主管機關為財政部  ⑤商業會計業務事件主管機關為經濟 部商業司  ⑥記帳士懲戒委員會處理懲戒事件，認為有犯罪嫌疑者，由記帳士懲戒委員會偵辦  ⑦商 業登記業務事件主管機關為財政部"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00323', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '記帳士、記帳及報稅代理人有下列情形之一者，依記帳士暨記帳及報稅代理人防制洗錢與打擊資恐辦 法第10條第1項規定不須向法務部調查局申報？', '["酬金高於新臺幣四十萬元，有正當理由以現金、外幣現金、旅行支票、外幣匯票或其他無記名金融 工具支付", "酬金高於新臺幣五十萬元，客戶無正當理由，自行或要求多次或連續以低於新臺幣五十萬元之現金 支付", "明知無該客戶存在或有事實足認該客戶身分遭冒用", "客戶為自然人，無正當理由拒絕與記帳士、記帳及報稅代理人見面或直接聯繫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00324', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '為維持記帳士專業能力及服務之效果與品質，張記帳士投資自己至某大學會計研究所進修，並依照法令 及財政部發布之其他攸關資料提供記帳士服務，此行為符合記帳士職業倫理道德規範中何項準則？', '["誠正準則之適任", "基本原則之適任", "行為準則之適任", "務實準則之適任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00325', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '下列有關記帳士職業倫理道德規範之敘述何者錯誤？', '["記帳士不得聘僱他記帳士事務所之現職人員", "記帳士設立分事務所，均應由記帳士親自主持，不得委由助理員或其他人變相主持", "凡違背記帳士職業倫理道德規範者，由所屬地方記帳士公會處理之", "記帳士事務所名稱不得與已登錄之事務所名稱相同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00326', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '下列有關記帳士之行為準則中，何者符合「適任」？①應遵守法律並依照法律及記帳士專業之要求辦', '["避免接受任何可能損害或被視為損害其專業判斷之特殊利益", "應持續進修以維持 記帳士專業能力及服務之效果與品質", "應依照法令及財政部發布之其他攸關資料提供記帳士服務", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00327', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '記帳士應遵守之原則，不包括下列何者？', '["記帳士於蒐集、評估及溝通有關受任人委任工作之資訊時，應表現最高度之專業務實性", "記帳士對所有攸關情況之評估應力求平衡，在作成判斷時不受個人利益或他人之不當影響", "記帳士於提供委任人服務時，應能運用所需之知識、技能及經驗", "記帳士應尊重其所獲得資訊之價值及所有權，且不得揭露此等資訊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00328', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '書面之行政處分，符合一定情形者，得不記明理由，下列何者不包括在內？', '["一般處分經公告或刊登政府公報或新聞紙", "有關專門知識、技能或資格所為之考試、檢定或鑑定等程序", "處分相對人或利害關係人無待處分機關之說明已知悉或可知悉作成處分之理由", "限制人民之權益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00329', 'bookkeeper', 'bookkeeper-moex-112-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '公法上之請求權，於請求權人假設為稅捐處，無法律另有規定，於111年8月1日已將111年房屋稅單 合法送達欠稅人，依行政程序法第131條規定，該筆欠稅若至何時不移送強制執行其請求權即消滅？', '["113年8月1日消滅", "114年8月1日消滅", "115年8月1日消滅", "116年8月1日消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "6ea954918b60", "answer_pdf_sha1": "662fc16cd058", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
